13	
14	* {
15	  margin: 0;
16	  padding: 0;
17	  box-sizing: border-box;
18	  -webkit-font-smoothing: antialiased;
19	  -moz-osx-font-smoothing: grayscale;
20	}
21	
22	html,
23	body {
24	  background: #050505;
25	  color: #fff;
26	  font-family: 'Inter', system-ui, -apple-system, sans-serif;
27	  font-weight: 400;
