37	/* ─────────────────── Atmospheric background ─────────────────── */
38	.hero-bg {
39	  position: fixed;
40	  inset: 0;
41	  z-index: 0;
42	  background:
43	    /* central spotlight */
44	    radial-gradient(
45	      ellipse 50% 45% at 50% 38%,
46	      color-mix(in srgb, var(--glow) 18%, transparent),
47	      transparent 70%
48	    ),
49	    /* mid warmth */
50	    radial-gradient(
51	      ellipse 80% 70% at 50% 50%,
52	      var(--bg-mid),
53	      transparent 65%
54	    ),
55	    /* deep base */
56	    radial-gradient(
57	      ellipse 130% 110% at 50% 85%,
58	      var(--bg-deep),
59	      transparent 60%
60	    ),
61	    /* edge vignette */
62	    radial-gradient(
63	      ellipse 100% 100% at 50% 50%,
64	      transparent 40%,
65	      rgba(0, 0, 0, 0.85) 100%
66	    ),
67	    #050505;
68	  background-blend-mode: screen, normal, normal, multiply, normal;
69	  transition: background-color 0.4s ease;
