134	
135	/* ─────────────────── Typography ─────────────────── */
136	.font-display {
137	  font-family: 'Anton', 'Bebas Neue', sans-serif;
138	  font-weight: 400;
139	  letter-spacing: -0.02em;
140	  text-transform: uppercase;
