142	}
143	
144	.font-mono-spec {
145	  font-family: 'JetBrains Mono', monospace;
146	  font-weight: 400;
147	  letter-spacing: 0.15em;
148	  text-transform: uppercase;
149	  font-size: 0.7rem;
150	}
151	
152	.font-body {
153	  font-family: 'Inter', sans-serif;
154	  font-weight: 400;
155	  letter-spacing: -0.005em;
156	}
157	
158	/* ─────────────────── Components ─────────────────── */
159	.glass {
160	  background: rgba(255, 255, 255, 0.04);
161	  backdrop-filter: blur(20px) saturate(1.2);
162	  -webkit-backdrop-filter: blur(20px) saturate(1.2);
163	  border: 1px solid rgba(255, 255, 255, 0.08);
164	}
165	
166	.glass-strong {
167	  background: rgba(255, 255, 255, 0.06);
168	  backdrop-filter: blur(24px) saturate(1.4);
169	  -webkit-backdrop-filter: blur(24px) saturate(1.4);
170	  border: 1px solid rgba(255, 255, 255, 0.1);
171	}
172	
173	/* Dome card */
174	.dome-card {
175	  background: radial-gradient(
176	    circle at 30% 30%,
177	    color-mix(in srgb, var(--card-glow, var(--glow)) 25%, transparent),
178	    color-mix(in srgb, var(--card-bg, var(--bg-mid)) 90%, black)
179	  );
180	  border: 1px solid rgba(255, 255, 255, 0.12);
181	  box-shadow:
182	    0 8px 20px rgba(0, 0, 0, 0.5),
183	    inset 0 1px 0 rgba(255, 255, 255, 0.1);
184	}
185	
186	.dome-card-active {
187	  border-color: color-mix(in srgb, var(--card-glow, var(--glow)) 80%, transparent);
188	  box-shadow:
189	    0 0 0 2px color-mix(in srgb, var(--card-glow, var(--glow)) 40%, transparent),
190	    0 0 30px color-mix(in srgb, var(--card-glow, var(--glow)) 60%, transparent),
191	    0 12px 30px rgba(0, 0, 0, 0.6),
192	    inset 0 1px 0 rgba(255, 255, 255, 0.2);
193	}
194	
195	/* CTA */
196	.cta-primary {
197	  background: rgba(255, 255, 255, 0.95);
198	  color: #000;
199	  font-family: 'JetBrains Mono', monospace;
200	  font-weight: 500;
201	  letter-spacing: 0.12em;
202	  text-transform: uppercase;
203	  font-size: 0.7rem;
204	  padding: 0.75rem 1.5rem;
205	  border-radius: 999px;
206	  transition: all 0.25s ease;
207	}
208	
209	.cta-primary:hover {
210	  background: var(--glow);
211	  color: #fff;
212	  box-shadow: 0 0 30px color-mix(in srgb, var(--glow) 60%, transparent);
213	}
214	
215	/* Mood word fade (keyframe-based — avoids transitioning background shorthand
216	   which conflicts with background-clip: text) */
217	@keyframes moodWordFade {
218	  from { opacity: 0; transform: translateY(0); }
219	  to   { opacity: 0.85; transform: translateY(-3vh); }
220	}
221	.mood-word-fade {
222	  animation: moodWordFade 0.9s cubic-bezier(0.16, 1, 0.3, 1) both;
223	}
224	
225	/* Reduced motion */
226	@media (prefers-reduced-motion: reduce) {
227	  * {
228	    animation-duration: 0.01ms !important;
229	    transition-duration: 0.01ms !important;
230	  }
231	}
