12	  glow: string;
13	  delay?: number;
14	}
15	
16	export default function StatCounter({
17	  value,
18	  decimals = 0,
19	  suffix,
20	  label,
21	  sublabel,
22	  glow,
23	  delay = 0,
24	}: Props) {
25	  const numRef = useRef<HTMLDivElement>(null);
26	  const wrapRef = useRef<HTMLDivElement>(null);
27	  const played = useRef(false);
28	
29	  useEffect(() => {
30	    const el = numRef.current;
31	    const wrap = wrapRef.current;
32	    if (!el || !wrap) return;
33	
34	    const play = () => {
35	      if (played.current) return;
36	      played.current = true;
37	      const obj = { val: 0 };
38	      gsap.to(obj, {
39	        val: value,
40	        duration: 1.6,
41	        delay,
42	        ease: 'power2.out',
43	        onUpdate: () => {
44	          el.textContent = obj.val.toFixed(decimals);
45	        },
46	      });
47	    };
48	
49	    const obs = new IntersectionObserver(
50	      ([entry]) => { if (entry.isIntersecting) play(); },
51	      { threshold: 0.3 }
52	    );
53	    obs.observe(wrap);
54	    return () => obs.disconnect();
55	  }, [value, decimals, delay]);
56	
57	  return (
58	    <div ref={wrapRef} className="stat-counter flex flex-col items-center" style={{ opacity: 0 }}>
59	      <div className="flex items-end gap-1" style={{ lineHeight: 0.85 }}>
60	        <div
61	          ref={numRef}
62	          className="font-display"
63	          style={{ fontSize: 'clamp(4rem, 9vw, 9rem)', color: glow, letterSpacing: '-0.04em' }}
64	        >
65	          0
66	        </div>
67	        <div
68	          className="font-display text-white/50 pb-2"
